mapper.update:
update addresses
set is_default = 0
where user_id = #{userId}

update addresses
set receiver_name  = #{addresses.receiverName},
    receiver_phone = #{addresses.receiverPhone},
    detail_address = #{addresses.detailAddress},
    is_default     = #{addresses.isDefault}
where address_id = #{addresses.addressId}
  and user_id = #{userId}
